# --- grid helper (hidden) — a binary counter built from decimal_to_4bit ---
# Laid out wide (the canvas has more room sideways): each COLUMN is a number
# 0..15; read down the column for its 8s/4s/2s/1s bits, lit by the student's own
# decimal_to_4bit(n). Until it works the bit cells show '?'; the number row and
# place-value labels always render.
def __grid():
    fn = globals().get("decimal_to_4bit")
    nums = list(range(16))

    def bits_of(n):
        if fn is None:
            return None
        try:
            r = fn(n)
            if r is not None and len(r) == 4:
                return list(r)
        except Exception:
            return None
        return None

    allbits = [bits_of(n) for n in nums]

    def cell(bits, i):
        if bits is None:
            return "?"
        if bits[i] == 1:
            return "blue"
        if bits[i] == 0:
            return ""
        return "?"

    rows = [["n"] + [str(n) for n in nums]]
    for i, place in enumerate(["8", "4", "2", "1"]):
        rows.append([place] + [cell(allbits[n], i) for n in nums])
    return {
        "grid": rows,
        "caption": "Each column is a number 0-15 in 4-bit binary - read down the column: 8s, 4s, 2s, 1s - built by your decimal_to_4bit. A blue square means that place-value bit is 1. A ? means decimal_to_4bit isn't finished yet.",
    }
